const r = $input.first().json.report || {};
const s = r.snapshot || {};
const rc = r.recent_critical || [];
const tops = r.top_ips_24h || [];
const bls = r.blocklist_active || [];
const sevColor = { critical: '#7f1d1d', high: '#dc2626', medium: '#ea580c', low: '#f59e0b', info: '#6b7280' };
const card = (label, value, color) => '<div style="background:'+(color||'#f9fafb')+';padding:12px 16px;border-radius:8px;flex:1;min-width:140px"><div style="font-size:11px;color:#6b7280;text-transform:uppercase;letter-spacing:.5px">'+label+'</div><div style="font-size:24px;font-weight:bold;color:#1f2937;margin-top:4px">'+(value!=null?value:'-')+'</div></div>';
const row = (cells) => '<tr>'+cells.map(c=>'<td style="padding:8px;border-bottom:1px solid #e5e7eb;font-size:13px">'+c+'</td>').join('')+'</tr>';
const recentRows = rc.length>0 ? rc.map(e=>row([
  '<span style="background:'+(sevColor[e.severity]||'#6b7280')+';color:white;padding:2px 8px;border-radius:3px;font-size:10px;text-transform:uppercase">'+e.severity+'</span>',
  e.event_type,
  e.source_ip||'-',
  (e.description||'').slice(0,80),
  new Date(e.occurred_at).toISOString().slice(0,16).replace('T',' ')
])).join('') : row(['<i style="color:#10b981">Sin eventos high/critical sin resolver</i>','','','','']);
const blsRows = bls.length>0 ? bls.map(b=>row([
  '<code>'+b.source_ip+'</code>',
  String(b.hit_count),
  (b.reason||'').slice(0,40),
  new Date(b.blocked_until).toISOString().slice(0,10)
])).join('') : row(['<i style="color:#10b981">Sin IPs bloqueadas activas</i>','','','']);
const topRows = tops.length>0 ? tops.slice(0,8).map(t=>row([
  '<code>'+t.source_ip+'</code>', String(t.hits), String(t.denied||0)
])).join('') : row(['<i style="color:#6b7280">Sin acceso registrado en 24h</i>','','']);
const html = '<!DOCTYPE html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>ArquitAI Security Dashboard</title>' +
'<style>body{font-family:-apple-system,Arial,sans-serif;max-width:1100px;margin:24px auto;padding:16px;color:#1f2937;background:#f3f4f6}h1{color:#0f172a;margin:0 0 8px}h2{color:#374151;font-size:16px;margin:24px 0 8px}.cards{display:flex;gap:12px;flex-wrap:wrap;margin:16px 0}table{width:100%;border-collapse:collapse;background:white;border-radius:8px;overflow:hidden}thead{background:#1f2937;color:white}thead th{padding:10px 8px;text-align:left;font-size:12px}.meta{color:#64748b;font-size:13px}.refresh{display:inline-block;background:#2563eb;color:white;padding:6px 12px;border-radius:4px;text-decoration:none;font-size:13px;margin-left:8px}</style>' +
'</head><body>' +
'<h1>ArquitAI Security Dashboard <a class="refresh" href="javascript:location.reload()">Refrescar</a></h1>' +
'<div class="meta">Snapshot generado ' + new Date().toLocaleString('es-ES') + '</div>' +
'<div class="cards">' +
  card('Critical sin resolver', s.critical_unresolved||0, (s.critical_unresolved||0)>0?'#fee2e2':null) +
  card('IPs blocked activas', r.blocklist_count||0, (r.blocklist_count||0)>0?'#fef3c7':null) +
  card('Bans en 24h', r.banned_24h||0) +
  card('Eventos 24h', s.events_last_24h||0) +
  card('Inj. attempts 24h', s.injection_attempts_24h||0, (s.injection_attempts_24h||0)>0?'#fee2e2':null) +
  card('GDPR pending', s.gdpr_pending||0) +
  card('Tokens activos', s.active_tokens||0) +
  card('Clientes sin consent', s.clients_without_consent||0, (s.clients_without_consent||0)>0?'#fee2e2':null) +
'</div>' +
'<h2>Eventos high/critical sin resolver</h2>' +
'<table><thead><tr><th>Sev</th><th>Tipo</th><th>IP</th><th>Descripcion</th><th>Cuando</th></tr></thead><tbody>'+recentRows+'</tbody></table>' +
'<h2>IPs en blocklist (top 10 por hits)</h2>' +
'<table><thead><tr><th>IP</th><th>Hits</th><th>Razon</th><th>Hasta</th></tr></thead><tbody>'+blsRows+'</tbody></table>' +
'<h2>Top IPs por accesos en 24h</h2>' +
'<table><thead><tr><th>IP</th><th>Hits</th><th>Denied</th></tr></thead><tbody>'+topRows+'</tbody></table>' +
'<p style="color:#94a3b8;font-size:11px;margin-top:32px;text-align:center">JSON crudo: <code>/webhook/security-dashboard</code> con header X-API-Key. Ultimo pen-test: '+(s.last_pen_test?new Date(s.last_pen_test).toISOString().slice(0,16):'(nunca)')+'</p>' +
'</body></html>';
return [{ json: { html: html } }];
